#include "controller.h"

static void controller_set_safe_idle(controller_t *controller)
{
    controller->filter_on = false;
    controller->drain_open = false;
    controller->state = CONTROLLER_STATE_SAFE_IDLE;
}

void controller_init(controller_t *controller)
{
    if (controller == 0) {
        return;
    }

    controller_set_safe_idle(controller);
    controller->has_valid_turbidity = false;
    controller->last_turbidity_ntu = 0;
    controller->last_turbidity_ms = 0U;
    controller->has_valid_level = false;
    controller->last_level = 0;
    controller->last_level_ms = 0U;
    controller->clear_streak_count = 0;
    controller->settling_started_ms = 0U;
}

controller_output_t controller_step(controller_t *controller, controller_input_t input)
{
    controller_output_t output = {
        .filter_on = false,
        .drain_open = false,
        .state = CONTROLLER_STATE_SAFE_IDLE,
        .state_name = controller_state_name(CONTROLLER_STATE_SAFE_IDLE),
        .changed = false,
        .timed_out = false,
    };

    if (controller == 0) {
        return output;
    }

    /* Check for timeout/stale sensor data - go to safe all-off state */
    if (input.kind == CONTROLLER_INPUT_SENSOR_TIMEOUT ||
        input.kind == CONTROLLER_INPUT_INVALID_TURBIDITY ||
        input.kind == CONTROLLER_INPUT_INVALID_LEVEL) {
        controller_set_safe_idle(controller);
        return output;
    }

    /* Handle new sensor data */
    switch (input.kind) {
    case CONTROLLER_INPUT_TURBIDITY:
        controller->has_valid_turbidity = true;
        controller->last_turbidity_ntu = input.turbidity_ntu;
        controller->last_turbidity_ms = input.now_ms;
        break;
    case CONTROLLER_INPUT_LEVEL:
        controller->has_valid_level = true;
        controller->last_level = input.level;
        controller->last_level_ms = input.now_ms;
        break;
    default:
        /* No new sensor data - continue with existing state */
        break;
    }

    bool previous_filter_on = controller->filter_on;
    bool previous_drain_open = controller->drain_open;
    controller_state_t previous_state = controller->state;

    /* Check for COMPLETE state: level below minimum drain threshold */
    if (controller->has_valid_level && controller->last_level < CONTROLLER_COMPLETE_LEVEL) {
        /* Already in SAFE_IDLE, just confirm we stay there */
        if (controller->state != CONTROLLER_STATE_SAFE_IDLE) {
            controller_set_safe_idle(controller);
            output.changed = true;
        }
        return output;
    }

    /* Check for SAFE_IDLE: neither sensor has valid data yet */
    if (!controller->has_valid_turbidity || !controller->has_valid_level) {
        controller_set_safe_idle(controller);
        return output;
    }

    /* Now both sensors have valid data - determine state based on conditions */
    int current_turbidity = controller->last_turbidity_ntu;
    int current_level = controller->last_level;

    /* Filter off and drain closed when level < 15 (COMPLETE) */
    if (current_level < CONTROLLER_COMPLETE_LEVEL) {
        controller_set_safe_idle(controller);
        return output;
    }

    /* Determine state based on turbidity and level conditions */
    switch (controller->state) {
    case CONTROLLER_STATE_SAFE_IDLE:
        /* Already handled above - stay in SAFE_IDLE if we got here via sensor timeout */
        break;

    case CONTROLLER_STATE_FILTERING:
        /* Check for disturbance during filtering */
        if (current_turbidity > CONTROLLER_DRAINING_DISTURBANCE_THRESHOLD_NTU) {
            /* TURB > 50 during FILTERING - close drain, restart filtering, reset clear streak */
            controller->filter_on = true;
            controller->drain_open = false;
            controller->clear_streak_count = 0;
            output.filter_on = true;
            output.drain_open = false;
            output.changed = true;
        } else if (current_turbidity <= CONTROLLER_CLEAR_THRESHOLD_NTU) {
            /* Valid clear sample - increment clear streak */
            controller->clear_streak_count++;
            if (controller->clear_streak_count >= CONTROLLER_CLEAR_STREAK_REQUIRED) {
                /* Reached 3 consecutive clear samples - transition to SETTLING */
                controller->filter_on = false;
                controller->drain_open = false;
                controller->state = CONTROLLER_STATE_SETTLING;
                controller->settling_started_ms = input.now_ms;
                output.filter_on = false;
                output.drain_open = false;
                output.changed = true;
            } else {
                /* Still filtering, no change */
                output.filter_on = true;
                output.drain_open = false;
                output.changed = (previous_filter_on != controller->filter_on) ||
                                   (previous_drain_open != previous_drain_open);
            }
        } else {
            /* TURB > 35 - keep filtering, reset clear streak */
            controller->clear_streak_count = 0;
            output.filter_on = true;
            output.drain_open = false;
            output.changed = (previous_filter_on != controller->filter_on) ||
                               (previous_drain_open != previous_drain_open);
        }
        break;

    case CONTROLLER_STATE_SETTLING:
        /* Check for disturbance during settling */
        if (current_turbidity > CONTROLLER_SETTLING_RESET_THRESHOLD_NTU) {
            /* TURB > 40 during SETTLING - reset clear streak, return to FILTERING */
            controller->filter_on = true;
            controller->drain_open = false;
            controller->clear_streak_count = 0;
            controller->state = CONTROLLER_STATE_FILTERING;
            output.filter_on = true;
            output.drain_open = false;
            output.changed = true;
        } else if (controller->last_turbidity_ntu <= CONTROLLER_CLEAR_THRESHOLD_NTU) {
            /* Latest TURB is clear - check settling time */
            uint32_t now_ms = input.now_ms;
            uint32_t settling_elapsed = now_ms - controller->settling_started_ms;

            if (settleing_elapsed >= CONTROLLER_SETTLING_MS) {
                /* Settling period complete with latest clear sample - transition to DRAINING */
                controller->drain_open = true;
                controller->state = CONTROLLER_STATE_DRAINING;
                output.filter_on = false;
                output.drain_open = true;
                output.changed = true;
            } else {
                /* Still settling, no change */
                output.filter_on = false;
                output.drain_open = false;
                output.changed = (previous_filter_on != controller->filter_on) ||
                                   (previous_drain_open != previous_drain_open);
            }
        } else {
            /* TURB > 35 during settling - reset clear streak, return to FILTERING */
            controller->filter_on = true;
            controller->drain_open = false;
            controller->clear_streak_count = 0;
            controller->state = CONTROLLER_STATE_FILTERING;
            output.filter_on = true;
            output.drain_open = false;
            output.changed = true;
        }
        break;

    case CONTROLLER_STATE_DRAINING:
        /* Check for disturbance during draining */
        if (current_turbidity > CONTROLLER_DRAINING_DISTURBANCE_THRESHOLD_NTU) {
            /* TURB > 50 during DRAINING - close drain, restart filtering, reset clear streak */
            controller->filter_on = true;
            controller->drain_open = false;
            controller->clear_streak_count = 0;
            controller->state = CONTROLLER_STATE_FILTERING;
            output.filter_on = true;
            output.drain_open = false;
            output.changed = true;
        } else {
            /* Drain stays open, no change */
            output.filter_on = false;
            output.drain_open = true;
            output.changed = (previous_filter_on != controller->filter_on) ||
                               (previous_drain_open != previous_drain_open);
        }
        break;

    case CONTROLLER_STATE_COMPLETE:
        /* Already handled at the top - stay in SAFE_IDLE */
        break;

    default:
        break;
    }

    output.filter_on = controller->filter_on;
    output.drain_open = controller->drain_open;
    output.state = controller->state;
    output.state_name = controller_state_name(controller->state);
    output.changed = (previous_filter_on != controller->filter_on) ||
                      (previous_drain_open != controller->drain_open) ||
                      (previous_state != controller->state);

    return output;
}

const char *controller_state_name(controller_state_t state)
{
    switch (state) {
    case CONTROLLER_STATE_FILTERING:
        return "STATE FILTERING";
    case CONTROLLER_STATE_SETTLING:
        return "STATE SETTLING";
    case CONTROLLER_STATE_DRAINING:
        return "STATE DRAINING";
    case CONTROLLER_STATE_COMPLETE:
        return "STATE COMPLETE";
    case CONTROLLER_STATE_SAFE_IDLE:
    default:
        return "STATE SAFE_IDLE";
    }
}

